import asyncio
import websockets

class InventorySystem:
    def __init__(self):
        self.items = {}

    async def add_item(self, item_id, player_id):
        if player_id not in self.items:
            self.items[player_id] = set()
        self.items[player_id].add(item_id)

    async def remove_item(self, item_id, player_id):
        if player_id in self.items and item_id in self.items[player_id]:
            self.items[player_id].remove(item_id)

    async def trade_items(self, sender_id, receiver_id, items):
        for item_id in items:
            if item_id not in self.items or sender_id not in self.items[item_id] or receiver_id not in self.items[item_id]:
                return False
        for item_id in items:
            self.remove_item(sender_id, item_id)
            self.add_item(receiver_id, item_id)
        return True

class PlayerInventoryManager:
    def __init__(self, player_id):
        self.player_id = player_id
        self.inventory = InventorySystem()

    async def add_item(self, item_id):
        await self.inventory.add_item(item_id, self.player_id)

    async def remove_item(self, item_id):
        await self.inventory.remove_item(item_id, self.player_id)

    async def trade_items(self, receiver_id, items):
        return await self.inventory.trade_items(self.player_id, receiver_id, items)

async def handle_client_request(websocket, path):
    data = await websocket.recv()
    player_id = int(data["playerId"])
    action = data["action"]
    if action == "addItem":
        item_id = int(data["itemId"])
        await PlayerInventoryManager(player_id).add_item(item_id)
    elif action == "removeItem":
        item_id = int(data["itemId"])
        await PlayerInventoryManager(player_id).remove_item(item_id)
    elif action == "tradeItems":
        receiver_id = int(data["receiverId"])
        items = [int(x) for x in data["items"].split(",")]
        if not await PlayerInventoryManager(player_id).trade_items(receiver_id, items):
            await websocket.send("Invalid item trade request")
    else:
        raise ValueError(f"Invalid action {action}")